h":0,"color":"#dc2626","expanded":false,"categories":[{"id":"cat_zhor1d0um","name":"Thương hiệu","description":"● Giới thiệu đại lý\n● Phỏng vấn đại lý và dự án thực tế\n● Câu chuyện đại lý bán tốt\n● Vinh danh đại lý tiêu biểu\n● Chia sẻ cách một đại lý tăng trưởng thật\n● Hỗ trợ nhận diện tại điểm bán (POSM, biển bảng, trưng bày)\n● Hỗ trợ đại lý trong hoạt động truyền thông\n● Hình ảnh thương hiệu thống nhất, chuyên nghiệp","allocation":10,"postsPerMonth":4,"topics":[],"expanded":false},{"id":"cat_4m3hdd5vi","name":"Chính sách bán","description":"● Chương trình sale/ khuyến mãi/ giảm giá\n● Hỗ trợ tư vấn bán hàng & đào tạo sản phẩm định kỳ","allocation":10,"postsPerMonth":4,"topics":[],"expanded":false}]},{"id":"1776766677199","name":"education khách hàng cuối","role":"","goal":"","description":"● Giới thiệu sản phẩm Seajong đến với khách hàng. Đưa ra các tính năng công nghệ đột phá của sản phẩm Seajong nhằm nâng cao chất lượng sống cho khách hàng\n● Seajong là chuyên gia trong ngành thiết bị vệ sinh và nhà bếp, cung cấp nhiều thông tin hữu ích cho khách hàng\n● Đưa ra các vấn đề mà khách hàng có thể gặp phải trong quá trình mua hàng, sử dụng hàng hoá và cung cấp các giải pháp để giải quyết cho khách hàng\n● Xây dựng niềm tin cho khách hàng nhờ có sản phẩm chất lượng tốt, đội ngũ chuyên nghiệp, dịch vụ - chính sách chăm sóc vượt trội","allocation":60,"postsPerMonth":0,"color":"#0891b2","expanded":false,"categories":[{"id":"cat_cry9tu4t4","name":"Sản phẩm","description":"● Giới thiệu sản phẩm\n● Đặc điểm nổi bật\n● Top các sản phẩm bán chạy\n● Top các sản phẩm hot\n● Tính năng - công nghệ mới đột phá\n● Sản phẩm mới","allocation":20,"postsPerMonth":7,"topics":[],"expanded":false},{"id":"cat_fqbnlhsli","name":"Chuyên gia","description":"● Diện tích phòng tắm nhỏ bố trí thế nào?\n● Diện tích phòng tắm master bố trí thế nào?\n● Cách bố trí tối ưu diện tích?\n● Tiêu chí lựa chọn thiết bị vệ sinh / nhà bếp bền đẹp\n● Tips vệ sinh giúp thiết bị bền đẹp theo thời gian\n● So sánh chất liệu, tính năng, công nghệ\n● Hướng dẫn sử dụng & bảo quản thiết bị đúng cách\n● Hướng dẫn lắp đặt","allocation":15,"postsPerMonth":5,"topics":[],"expanded":false},{"id":"cat_lcvesu7ic","name":"Nỗi đau","description":"● Mua thiết bị đẹp nhưng nhanh xuống cấp\n● Không biết chọn sản phẩm phù hợp diện tích\n● Thiết bị khó vệ sinh, nhanh ố vàng, oxi hóa\n● Không phân biệt được chất liệu tốt – kém khi mua hàng\n● Lo ngại vấn đề bảo hành, hậu mãi sau khi mua\n● Sợ mua phải hàng không rõ nguồn gốc, không hóa đơn\n● Bị hấp dẫn bởi giá rẻ, sau đó tốn chi phí sửa chữa, thay thế\n● Mua thiết bị rời rạc, thiếu đồng bộ tổng thể\n● Khó sửa – khó thay – khó tìm linh kiện\n● Không có kỹ thuật, hướng dẫn lắp đặt, sử dụng","allocation":15,"postsPerMonth":5,"topics":[],"expanded":false},{"id":"cat_cxi4xesd8","name":"Xây dựng niềm tin","description":"● Sản phẩm có xuất xứ minh bạch, hóa đơn đầy đủ\n● Danh mục sản phẩm được chọn lọc kỹ càng\n● Thiết bị được thiết kế cho sử dụng lâu dài\n● Đội ngũ tư vấn có chuyên môn, thấu hiểu khách hàng\n● Có showroom trưng bày thật để khách trải nghiệm trước khi mua\n● Chính sách bảo hành minh bạch, dễ hiểu, dễ thực hiện\n● Có video, hình ảnh hướng dẫn lắp đặt, sử dụng chi tiết\n● Quy trình sản xuất\n● Quy trình bảo hành sản phẩm\n● Quy trình đóng gói\n● Review / Feedback khách hàng","allocation":10,"postsPerMonth":4,"topics":[],"expanded":false}]}],"monthlyPlans":{},"partialUpdateMonthly":false}',0);
